import React, { useState, useCallback, useEffect } from 'react';
import { VietQROptions } from '@viet-qr/core';
import { VietQR } from './VietQR';

export interface VietQRButtonProps extends VietQROptions {
  /**
   * Nhãn hiển thị trên nút bấm. Mặc định: "Thanh toán VietQR"
   */
  label?: string;
  /**
   * Kích thước QR hiển thị trong modal (pixel). Mặc định: 260
   */
  size?: number;
  /**
   * Giao diện màu sắc của nút. Mặc định: 'default'
   */
  variant?: 'default' | 'outline' | 'ghost';
  /**
   * Giao diện sáng/tối của Modal hiển thị QR. Mặc định: 'light'
   */
  theme?: 'light' | 'dark';
  /**
   * CSS class tùy chỉnh cho nút bấm
   */
  className?: string;
  /**
   * Callback khi modal mở
   */
  onOpen?: () => void;
  /**
   * Callback khi modal đóng
   */
  onClose?: () => void;
}

const styles = {
  btn: {
    display: 'inline-flex',
    alignItems: 'center',
    gap: '8px',
    padding: '10px 20px',
    borderRadius: '10px',
    fontSize: '15px',
    fontWeight: 600,
    cursor: 'pointer',
    border: 'none',
    fontFamily: 'inherit',
    transition: 'all 0.2s ease',
  },
  btnDefault: {
    background: 'linear-gradient(135deg, #0051cc 0%, #0070f3 100%)',
    color: '#ffffff',
    boxShadow: '0 2px 8px rgba(0, 112, 243, 0.35)',
  },
  btnOutline: {
    background: 'transparent',
    color: '#0070f3',
    border: '2px solid #0070f3',
  },
  btnGhost: {
    background: 'rgba(0, 112, 243, 0.08)',
    color: '#0070f3',
    border: 'none',
  },
  overlay: {
    position: 'fixed' as const,
    inset: 0,
    background: 'rgba(0, 0, 0, 0.6)',
    backdropFilter: 'blur(4px)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    zIndex: 9999,
    padding: '16px',
    animation: 'vqr-fade-in 0.2s ease',
  },
  modal: {
    background: '#ffffff',
    borderRadius: '20px',
    padding: '28px 24px 24px',
    width: '100%',
    maxWidth: '340px',
    position: 'relative' as const,
    boxShadow: '0 20px 60px rgba(0, 0, 0, 0.2)',
    animation: 'vqr-slide-up 0.25s ease',
  },
  modalDark: {
    background: '#1a1a2e',
    color: '#ffffff',
  },
  modalTitleDark: {
    color: '#ffffff',
  },
  closeBtnDark: {
    background: 'rgba(255,255,255,0.1)',
    color: '#e2e8f0',
  },
  qrWrapperDark: {
    background: '#0f0f1e',
  },
  hintDark: {
    color: '#a3a3b8',
  },
  closeBtn: {
    position: 'absolute' as const,
    top: '14px',
    right: '16px',
    background: 'rgba(0,0,0,0.07)',
    border: 'none',
    borderRadius: '50%',
    width: '32px',
    height: '32px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    cursor: 'pointer',
    fontSize: '18px',
    lineHeight: 1,
    color: '#666',
  },
  modalTitle: {
    textAlign: 'center' as const,
    marginBottom: '16px',
    fontWeight: 700,
    fontSize: '17px',
    color: '#000',
  },
  qrWrapper: {
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    padding: '12px',
    background: '#f8f9fa',
    borderRadius: '12px',
    marginBottom: '16px',
  },
  hint: {
    textAlign: 'center' as const,
    fontSize: '13px',
    color: '#888',
  },
};

// Inject keyframes once
let stylesInjected = false;
function injectStyles() {
  if (stylesInjected || typeof document === 'undefined') return;
  const style = document.createElement('style');
  style.textContent = `
    @keyframes vqr-fade-in { from { opacity: 0 } to { opacity: 1 } }
    @keyframes vqr-slide-up { from { transform: translateY(20px); opacity: 0 } to { transform: translateY(0); opacity: 1 } }
    .vqr-btn:hover { filter: brightness(1.08); transform: translateY(-1px); }
    .vqr-btn:active { transform: translateY(0); }
    .vqr-close-btn:hover { background: rgba(0,0,0,0.14) !important; }
  `;
  document.head.appendChild(style);
  stylesInjected = true;
}

/**
 * Nút bấm "Thanh toán VietQR" tích hợp Modal hiển thị mã QR.
 * Khi click, một Modal sẽ hiện ra chứa QR code để người dùng quét thanh toán.
 *
 * @example
 * <VietQRButton
 *   bankId="VCB"
 *   accountNo="1234567890"
 *   accountName="NGUYEN VAN A"
 *   amount={50000}
 *   label="Thanh toán ngay"
 * />
 */
export const VietQRButton: React.FC<VietQRButtonProps> = ({
  label = 'Thanh toán VietQR',
  size = 260,
  variant = 'default',
  theme = 'light',
  className,
  onOpen,
  onClose,
  ...qrOptions
}) => {
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    injectStyles();
  }, []);

  // Close on Escape key
  useEffect(() => {
    if (!isOpen) return;
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape') handleClose();
    };
    document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
  }, [isOpen]);

  // Prevent body scroll when modal open
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }
    return () => { document.body.style.overflow = ''; };
  }, [isOpen]);

  const handleOpen = useCallback(() => {
    setIsOpen(true);
    onOpen?.();
  }, [onOpen]);

  const handleClose = useCallback(() => {
    setIsOpen(false);
    onClose?.();
  }, [onClose]);

  const variantStyle = variant === 'outline'
    ? styles.btnOutline
    : variant === 'ghost'
      ? styles.btnGhost
      : styles.btnDefault;

  const formattedAmount = qrOptions.amount
    ? new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(qrOptions.amount)
    : null;

  const isDark = theme === 'dark';

  return (
    <>
      <button
        className={`vqr-btn${className ? ` ${className}` : ''}`}
        style={{ ...styles.btn, ...variantStyle }}
        onClick={handleOpen}
        type="button"
      >
        {/* QR Icon */}
        <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
          <rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/>
          <line x1="14" y1="14" x2="14" y2="14"/><line x1="17" y1="14" x2="17" y2="14"/><line x1="20" y1="14" x2="20" y2="14"/>
          <line x1="14" y1="17" x2="14" y2="17"/><line x1="17" y1="17" x2="20" y2="17"/>
          <line x1="20" y1="20" x2="20" y2="20"/>
        </svg>
        {label}
      </button>

      {isOpen && (
        <div style={styles.overlay} onClick={handleClose} role="dialog" aria-modal="true">
          <div style={{ ...styles.modal, ...(isDark ? styles.modalDark : null) }} onClick={(e) => e.stopPropagation()}>
            <button
              className="vqr-close-btn"
              style={{ ...styles.closeBtn, ...(isDark ? styles.closeBtnDark : null) }}
              onClick={handleClose}
              aria-label="Đóng"
            >
              ✕
            </button>
            <p style={{ ...styles.modalTitle, ...(isDark ? styles.modalTitleDark : null) }}>Quét mã để thanh toán</p>
            <div style={{ ...styles.qrWrapper, ...(isDark ? styles.qrWrapperDark : null) }}>
              <VietQR {...qrOptions} size={size} renderAs="svg" level="Q" />
            </div>
            {formattedAmount && (
              <p style={{ ...styles.hint, fontWeight: 700, fontSize: '16px', color: '#0070f3', marginBottom: '6px' }}>
                {formattedAmount}
              </p>
            )}
            {qrOptions.accountName && (
              <p style={{ ...styles.hint, ...(isDark ? styles.hintDark : null), marginBottom: '4px' }}>
                {qrOptions.accountName}
              </p>
            )}
            <p style={{ ...styles.hint, ...(isDark ? styles.hintDark : null) }}>{qrOptions.accountNo}</p>
          </div>
        </div>
      )}
    </>
  );
};
